static inline long long get_time_local() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

__global__ void kernel_cuda_1(record *records,
                              knode *knodes,
                              long knodes_elem,
                              int order,
                              long maxheight,
                              int count,
                              long *currKnode,
                              long *offset,
                              int *keys,
                              record *ans,
                              int threadsPerBlock) {
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count || thid >= threadsPerBlock) return;

    for (int i = 0; i < maxheight; i++) {
        if ((knodes[currKnode[bid]].keys[thid] <= keys[bid]) &&
            (knodes[currKnode[bid]].keys[thid + 1] > keys[bid])) {
            if (knodes[offset[bid]].indices[thid] < knodes_elem) {
                offset[bid] = knodes[offset[bid]].indices[thid];
            }
        }

        __syncthreads();
        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }
        __syncthreads();
    }

    if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
        ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
    }
}

void
kernel_cpu(  int cores_arg,
             record *records,
             knode *knodes,
             long knodes_elem,
             int order,
             long maxheight,
             int count,
             long *currKnode,
             long *offset,
             int *keys,
             record *ans) {
    (void)cores_arg;

    long long time0 = get_time_local();

    setdevice();
    int threadsPerBlock = order < 1024 ? order : 1024;

    long long time1 = get_time_local();

    record *d_records = NULL;
    knode *d_knodes = NULL;
    long *d_currKnode = NULL;
    long *d_offset = NULL;
    int *d_keys = NULL;
    record *d_ans = NULL;

    size_t records_bytes = (size_t)size * sizeof(record);
    size_t knodes_bytes = (size_t)knodes_elem * sizeof(knode);
    size_t long_bytes = (size_t)count * sizeof(long);
    size_t int_bytes = (size_t)count * sizeof(int);
    size_t ans_bytes = (size_t)count * sizeof(record);

    cudaMalloc((void **)&d_records, records_bytes);
    cudaMalloc((void **)&d_knodes, knodes_bytes);
    cudaMalloc((void **)&d_currKnode, long_bytes);
    cudaMalloc((void **)&d_offset, long_bytes);
    cudaMalloc((void **)&d_keys, int_bytes);
    cudaMalloc((void **)&d_ans, ans_bytes);

    cudaMemcpy(d_records, records, records_bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, knodes_bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, long_bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, long_bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, int_bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ans, ans, ans_bytes, cudaMemcpyHostToDevice);

    if (count > 0) {
        dim3 grid((unsigned int)count, 1, 1);
        dim3 block((unsigned int)threadsPerBlock, 1, 1);
        kernel_cuda_1<<<grid, block>>>(d_records, d_knodes, knodes_elem, order, maxheight, count,
                                       d_currKnode, d_offset, d_keys, d_ans, threadsPerBlock);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(ans, d_ans, ans_bytes, cudaMemcpyDeviceToHost);
    cudaMemcpy(currKnode, d_currKnode, long_bytes, cudaMemcpyDeviceToHost);
    cudaMemcpy(offset, d_offset, long_bytes, cudaMemcpyDeviceToHost);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

    long long time2 = get_time_local();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
           (float)(time1 - time0) / 1000000.0f,
           (float)(time1 - time0) / (float)(time2 - time0) * 100.0f);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
           (float)(time2 - time1) / 1000000.0f,
           (float)(time2 - time1) / (float)(time2 - time0) * 100.0f);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2 - time0) / 1000000.0f);
}

